import { Link, useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();
  const userInfo = JSON.parse(localStorage.getItem("userInfo"));

  const handleLogout = () => {
    localStorage.removeItem("userInfo");
    navigate("/login");
    window.location.reload();
  };

  return (
    <nav style={{ padding: "12px 20px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
      <div>
        <Link to="/" style={{ color: "black", marginRight: 15 }}>Home</Link>
        <Link to="/matches" style={{ color: "black", marginRight: 15 }}>Matches</Link>
        <Link to="/players" style={{ color: "white", marginRight: 15 }}>Players</Link>
        <Link to="/teams" style={{ color: "white", marginRight: 15 }}>Teams</Link>
        {userInfo && (
          <>
            <Link to="/add-match" style={{ color: "white", marginRight: 15 }}>Add Match</Link>
            <Link to="/add-player" style={{ color: "white", marginRight: 15 }}>Add Player</Link>
          </>
        )}
      </div>
      <div>
        {userInfo ? (
          <>
            {userInfo.isAdmin && <Link to="/admin" style={{ color: "white", marginRight: 15, background: '#f57c00', padding: '4px 8px', borderRadius: '4px' }}>Admin</Link>}
            <span style={{ color: "white", marginRight: 15 }}>Hi, {userInfo.username}</span>
            <button onClick={handleLogout} style={{ background: "black", border: "1px solid white", color: "white", padding: "5px 10px", borderRadius: "4px", cursor: "pointer" }}>Logout</button>
          </>
        ) : (
          <>
            <Link to="/login" style={{ color: "white", marginRight: 15 }}>Login</Link>
            <Link to="/register" style={{ color: "white", border: "1px solid white", padding: "5px 10px", borderRadius: "4px" }}>Register</Link>
          </>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
